// src/services/auth-service.ts
var generateSlug = (storeName) => {
  return storeName.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
};
var checkEmailExists = async (email3) => {
  const user = await db.query.users.findFirst({
    where: eq(users.email, email3)
  });
  return !!user;
};
var hashPassword = async (password) => {
  return await bcryptjs_default.hash(password, 10);
};
var registerVendor = async (payload) => {
  const { name, email: email3, password, storeName, phone } = payload;
  const emailExists = await checkEmailExists(email3);
  if (emailExists)
    throw new Error("Email already in use");
  const passwordHash = await hashPassword(password);
  const slug = generateSlug(storeName);
  await db.transaction(async (tx) => {
    const [user] = await tx.insert(users).values({
      name,
      email: email3,
      passwordHash,
      role: "vendor"
    }).returning();
    await tx.insert(vendors).values({
      userId: user.id,
      storeName,
      phone,
      logoUrl: null,
      slug
    });
  });
  await sendApprovalPendingEmail(name, email3, slug);
};
var loginVendor = async (email3, password) => {
  const user = await db.query.users.findFirst({
    where: eq(users.email, email3),
    with: {
      vendor: true
    }
  });
  if (!user)
    throw new Error("Invalid credentials");
  const validPassword = await bcryptjs_default.compare(password, user.passwordHash);
  if (!validPassword)
    throw new Error("Invalid credentials");
  if (user.role !== "admin" && !user.vendor?.approved) {
    throw new Error("Account pending approval");
  }
  const token = await sign2({ userId: user.id, role: user.role }, process.env.JWT_SECRET, "HS256");
  return { token, user };
};
var getCurrentUser = async (userId) => {
  const user = await db.query.users.findFirst({
    where: eq(users.id, userId),
    with: { vendor: true }
  });
  if (!user)
    throw new Error("User not found");
  return user;
};
var getAllVendors = async () => {
  return await db.query.vendors.findMany({
    with: { user: true }
  });
};
var getPendingVendors = async () => {
  return await db.query.vendors.findMany({
    where: eq(vendors.approved, false),
    with: { user: true }
  });
};
var getApprovedVendors = async () => {
  return await db.query.vendors.findMany({
    where: eq(vendors.approved, true),
    with: { user: true }
  });
};
var approveVendor = async (vendorId) => {
  const [vendor] = await db.update(vendors).set({
    approved: true,
    approvedAt: new Date
  }).where(eq(vendors.id, vendorId)).returning();
  if (!vendor)
    throw new Error("Vendor not found");
  const user = await db.query.users.findFirst({
    where: eq(users.id, vendor.userId)
  });
  if (user) {
    await sendApprovalEmail(user.name, user.email, vendor.slug);
  }
  return vendor;
};
var getVendorBySlug = async (slug) => {
  const vendor = await db.query.vendors.findFirst({
    where: eq(vendors.slug, slug),
    with: {
      products: {
        with: { images: true }
      }
    }
  });
  if (!vendor)
    throw new Error("Store not found");
  return vendor;
};

